import{_ as t,H as n,f as s,i}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"程序员的数学系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../mathForCS/00-写作计划.md","filePath":"../mathForCS/00-写作计划.md","lastUpdated":1779559313000}'),l={name:"../mathForCS/00-写作计划.md"};function e(o,a,r,d,p,u){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="程序员的数学系列写作计划" tabindex="-1">程序员的数学系列写作计划 <a class="header-anchor" href="#程序员的数学系列写作计划" aria-label="Permalink to &quot;程序员的数学系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」第十三项(M. mathForCS),⭐⭐⭐⭐。 aiLearning 第 02 篇只起了个头(向量 / 矩阵 / 概率 / 求导),写到 RAG 评测、量化、推理优化、分布式训练、RLHF 时全部撞墙——<strong>算法实现可以照抄,但选型、调参、排错、读论文都绕不开数学</strong>。securityLearning 的密码学一层、algorithmLearning 的复杂度分析、distributedLearning 的时钟与共识,底下也都是同一套数学。 <strong>看完这层,你看 LLM / 推荐 / 搜索 / 密码学 / 控制论的论文都能直接读到底</strong>——不是「会证」,而是「看到一行公式知道它在工程里是哪个开关、调它会动哪儿」。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「数与近似」到「离散与图」,<strong>每个抽象都立刻落到一个工程场景</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 基础(为什么工程师要懂数学 / 数的表示 / 误差与近似 / 公式到代码的翻译)</span></span>
<span class="line"><span>   → 线性代数(向量空间 / 矩阵变换 / 特征 / SVD / 张量与 einsum)</span></span>
<span class="line"><span>   → 概率与统计(分布 / 期望方差 / MLE/MAP / A/B 测试)</span></span>
<span class="line"><span>   → 信息论(熵 / 交叉熵与 KL / 互信息 / LLM 里的应用)</span></span>
<span class="line"><span>   → 微积分与凸优化(梯度 / 反向传播 / 凸性 / SGD/Adam / 拉格朗日对偶)</span></span>
<span class="line"><span>   → 离散数学(组合 / 图论 / 数论与密码学 / 马尔可夫 / 工具链)</span></span></code></pre></div><p><strong>这个系列不是大学《高等数学》《线性代数》《概率论》合订本</strong>——那些课本讲究&quot;完备 + 证明&quot;,本系列只讲究**&quot;工程师拿来即用 + 看懂论文 + 不被术语唬住&quot;**。每章只回答四个问题:<strong>这个东西想解决什么?它的几何/代数直觉是什么?在哪个工程系统里出现?调它会动什么?</strong></p><p>不证明——<strong>所有定理直接给结论 + 一张图 + 一段最小代码</strong>;不算题——<strong>所有&quot;算式&quot;都对应到 NumPy/PyTorch 一行代码或一个真实超参</strong>。读者画像是<strong>写过 ML / 后端 / 安全代码,数学课本翻不下去,但读 LoRA / vLLM / RSA / Raft 论文时被公式劝退的工程师</strong>。</p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-04" tabindex="-1">第一层:心智与基础(01-04) <a class="header-anchor" href="#第一层-心智与基础-01-04" aria-label="Permalink to &quot;第一层:心智与基础(01-04)&quot;">​</a></h3><ul><li>[x] 01 程序员的数学总览(为什么工程师要懂数学 / 三系列的地下室 / 不证明只用 / 这套系列怎么读)</li><li>[x] 02 数的表示与精度(IEEE 754 / FP32/FP16/BF16/FP8 / 定点与量化 / 精度损失的真实事故)</li><li>[x] 03 近似、误差与渐进分析(大 O 再访 / 收敛速率 / 数值稳定 / 工程里的&quot;差不多就行&quot;)</li><li>[x] 04 数学符号到代码的翻译(Σ Π ∇ ∂ ∈ → for / sum / grad / 看公式不慌的最小集)</li></ul><h3 id="第二层-线性代数-05-10" tabindex="-1">第二层:线性代数(05-10) <a class="header-anchor" href="#第二层-线性代数-05-10" aria-label="Permalink to &quot;第二层:线性代数(05-10)&quot;">​</a></h3><ul><li>[x] 05 向量与向量空间(几何直觉 / 内积 / 范数 L1/L2/L∞ / 词向量为什么用 cosine)</li><li>[x] 06 矩阵作为线性变换(变换不是数表 / 旋转/缩放/投影 / 神经网络一层 = 一个矩阵)</li><li>[x] 07 矩阵乘法的代价(GEMM / 分块 / 缓存 / 为什么 GPU 适合 / Roofline 模型)</li><li>[x] 08 特征值与特征向量(主方向 / PageRank / 谱分解 / 协方差矩阵)</li><li>[x] 09 SVD 与低秩近似(矩阵分解通用语言 / 推荐系统 / LoRA 为什么能压缩 / PCA 再访)</li><li>[x] 10 张量与 einsum(广播 / 形状对齐 / Transformer 里张量怎么流 / einsum 为什么不容易写错)</li></ul><h3 id="第三层-概率与统计-11-15" tabindex="-1">第三层:概率与统计(11-15) <a class="header-anchor" href="#第三层-概率与统计-11-15" aria-label="Permalink to &quot;第三层:概率与统计(11-15)&quot;">​</a></h3><ul><li>[x] 11 概率心智(频率 vs 贝叶斯 / 条件概率 / 独立性 / Monty Hall 与常见误用)</li><li>[x] 12 随机变量与常见分布(高斯 / 伯努利 / 泊松 / 长尾 / 分布选错的真实代价)</li><li>[x] 13 期望、方差与中心极限(为什么平方 / CLT 的工程含义 / Bootstrap 重采样)</li><li>[x] 14 极大似然、MAP 与贝叶斯推断(MLE / MAP / 后验 / 损失函数怎么从似然来 / 共轭先验)</li><li>[x] 15 假设检验与 A/B 测试(p 值真正含义 / 第一/二类错误 / 检验功效 / 多重比较陷阱)</li></ul><h3 id="第四层-信息论-16-19" tabindex="-1">第四层:信息论(16-19) <a class="header-anchor" href="#第四层-信息论-16-19" aria-label="Permalink to &quot;第四层:信息论(16-19)&quot;">​</a></h3><ul><li>[x] 16 信息熵(惊讶度的度量 / 编码下界 / Huffman / 为什么压缩有极限)</li><li>[x] 17 交叉熵与 KL 散度(分类损失为什么是它 / KL 非对称 / RLHF 里的 KL 罚项)</li><li>[x] 18 互信息与特征选择(变量间共享多少信息 / 特征工程 / 表示学习里的目标)</li><li>[x] 19 信息论在 ML / LLM 里的应用(Tokenizer 与压缩边界 / 信息瓶颈 / 模型容量度量)</li></ul><h3 id="第五层-微积分与凸优化-20-24" tabindex="-1">第五层:微积分与凸优化(20-24) <a class="header-anchor" href="#第五层-微积分与凸优化-20-24" aria-label="Permalink to &quot;第五层:微积分与凸优化(20-24)&quot;">​</a></h3><ul><li>[x] 20 导数、偏导与梯度(单变量到多变量 / 梯度方向 / 雅可比 / Hessian 的几何直觉)</li><li>[x] 21 链式法则与反向传播(BP 不是黑魔法 / 计算图 / autograd 是怎么实现的)</li><li>[x] 22 凸集与凸函数(凸为什么好解 / 局部即全局 / 神经网络非凸的代价与对策)</li><li>[x] 23 梯度下降族(SGD / Momentum / Adam / AdamW / 学习率与 warmup / 为什么这么调)</li><li>[x] 24 拉格朗日对偶与约束优化(KKT / SVM 对偶 / 对偶在工程上有什么实际用)</li></ul><h3 id="第六层-离散数学与工具链-25-30" tabindex="-1">第六层:离散数学与工具链(25-30) <a class="header-anchor" href="#第六层-离散数学与工具链-25-30" aria-label="Permalink to &quot;第六层:离散数学与工具链(25-30)&quot;">​</a></h3><ul><li>[x] 25 组合数学心智(排列组合 / 鸽笼 / 容斥 / 哈希冲突与生日攻击的估算)</li><li>[x] 26 图论基础(表示法 / BFS/DFS 的数学结构 / 连通性 / 最短路 / 最小生成树)</li><li>[x] 27 谱图与 PageRank(图的特征向量 / PageRank 收敛性 / GNN 的数学骨架)</li><li>[x] 28 数论与密码学(模运算 / 欧拉定理 / RSA / Diffie-Hellman / 椭圆曲线直觉)</li><li>[x] 29 马尔可夫链与随机过程(转移矩阵 / 平稳分布 / MCMC / RL 的 MDP 数学骨架)</li><li>[x] 30 数学工具链与下一步(NumPy / SciPy / SymPy / JAX / 工程师怎么继续学 / 推荐书单)</li></ul><hr><h2 id="关键概念到工程系统的索引" tabindex="-1">关键概念到工程系统的索引 <a class="header-anchor" href="#关键概念到工程系统的索引" aria-label="Permalink to &quot;关键概念到工程系统的索引&quot;">​</a></h2><p>每篇都明确给出&quot;这个数学概念落到哪个工程系统&quot;,写作时按这个清单倒着核对:</p><table tabindex="0"><thead><tr><th>层</th><th>关键数学</th><th>工程落地</th></tr></thead><tbody><tr><td>基础</td><td>IEEE 754 / 量化 / 数值稳定</td><td>FP8 训练、INT4 量化、log-sum-exp 技巧</td></tr><tr><td>线性代数</td><td>内积 / SVD / 特征分解 / 张量</td><td>Embedding 检索、LoRA、PCA、Attention、einsum</td></tr><tr><td>概率统计</td><td>MLE / MAP / 贝叶斯 / A/B</td><td>损失函数设计、推荐系统、实验平台、置信区间</td></tr><tr><td>信息论</td><td>熵 / 交叉熵 / KL / 互信息</td><td>分类损失、RLHF KL 罚项、Tokenizer 压缩比</td></tr><tr><td>微积分 / 优化</td><td>梯度 / BP / 凸性 / Adam / KKT</td><td>autograd、训练调参、SVM、约束优化</td></tr><tr><td>离散</td><td>图论 / 数论 / 马尔可夫</td><td>PageRank、RSA/ECC、HMM、MDP/RL、布隆过滤器</td></tr></tbody></table><hr><h2 id="读者画像" tabindex="-1">读者画像 <a class="header-anchor" href="#读者画像" aria-label="Permalink to &quot;读者画像&quot;">​</a></h2><p>本系列假设读者已具备:</p><ul><li>写过至少一段 ML / 后端 / 安全代码,见过 NumPy / PyTorch / 矩阵乘法的字面写法</li><li>高中数学没忘光(三角函数、指数对数、求导是认得的)</li><li>看过 aiLearning 第 02 篇或等价材料,知道&quot;向量、矩阵、求导&quot;在 ML 里是基础,但不知道为什么是这样</li><li><strong>不要求</strong>学过《数学分析》《抽象代数》;<strong>不要求</strong>会做证明题</li></ul><p>如果你完全没碰过 NumPy、不知道梯度下降在做什么、没读过任何一篇 ML 论文,建议先把 aiLearning 前 10 篇过一遍,再来这层补&quot;为什么&quot;。</p><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>神经网络 / 反向传播 / 优化器(实现层)</td><td>aiLearning/03-08 ✅</td><td>不重复,本系列讲<strong>底下的数学</strong>(20-23)</td></tr><tr><td>Transformer / Attention(架构层)</td><td>aiLearning/12-13 ✅</td><td>不重复,只在 10 讲里讲张量是怎么流的</td></tr><tr><td>RAG / Embedding / 向量数据库</td><td>aiLearning/22-23 ✅</td><td>不重复,只在 05 讲为什么用 cosine</td></tr><tr><td>LoRA / 量化 / 推理优化</td><td>aiLearning/18, 33 ✅</td><td>不重复,本系列讲<strong>底下的 SVD 与精度</strong>(02、09)</td></tr><tr><td>复杂度 / 算法分析</td><td>algorithmLearning/01-02 ✅</td><td>不重复,本系列只在 03 / 25 补&quot;渐进分析与组合估算&quot;的数学侧</td></tr><tr><td>一致性哈希 / 布隆过滤器</td><td>algorithmLearning ✅</td><td>不重复,本系列只点&quot;概率/哈希数学&quot;(25)</td></tr><tr><td>密码学算法实现 / Web 攻防</td><td>securityLearning ✅</td><td>不重复,本系列只讲<strong>底下的数论与代数</strong>(28)</td></tr><tr><td>时钟 / 共识 / 拜占庭</td><td>distributedLearning ✅</td><td>不重复,本系列不进协议层</td></tr><tr><td>GPU / CUDA / 推理引擎实现</td><td>(未来 aiInfra)</td><td>不交叉,本系列只到 Roofline 与 GEMM 直觉(07)</td></tr><tr><td>控制论 / 信号处理 / 傅里叶</td><td>(不写)</td><td>太离工程师日常,只在 18 顺手提互信息时点一下</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么 → 几何直觉 → 代码 → 工程对应&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么需要这个东西</span></span>
<span class="line"><span>   - 工程里在哪儿撞到的(具体场景:训练、推荐、密码学、A/B…)</span></span>
<span class="line"><span>   - 不懂它会犯什么错(真实事故 / 论文里的反例)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 直觉(一张图就讲明白)</span></span>
<span class="line"><span>   - 几何图 / 状态机 / 数据流,任选其一</span></span>
<span class="line"><span>   - 关键概念用最少的符号讲清楚</span></span>
<span class="line"><span>   - 把课本里的 ε-δ 翻译成&quot;差多少够用&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 代码(10-30 行 NumPy / PyTorch / SymPy)</span></span>
<span class="line"><span>   - 真能跑、真能改超参看动效</span></span>
<span class="line"><span>   - 标注「这一行换成 X 会发生什么」</span></span>
<span class="line"><span>   - 数值稳定的关键技巧(log-sum-exp / 减最大值 / 归一化)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 工程对应与局限</span></span>
<span class="line"><span>   - 这个数学落到哪个真实系统(PyTorch op / Faiss / RSA / PageRank)</span></span>
<span class="line"><span>   - 调它会动什么(超参映射到数学变量)</span></span>
<span class="line"><span>   - 何时不该用 / 何时该换更复杂的工具</span></span></code></pre></div><p>不堆证明——<strong>只贴关键不变量、几何图和最小代码</strong>,让读者「看到这一行公式知道它在工程里是哪个旋钮」就够了。</p><p>每篇遇到几何对象、数据流、状态变化,<strong>一定画图</strong>——线性代数 / 概率分布 / 计算图 / 图论不画图永远讲不清楚。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-04  心智:看完知道&quot;为什么 FP16 训练会 NaN、什么时候该担心数值稳定&quot;</span></span>
<span class="line"><span>05-10  线代:**最值钱的一层**,看完读 Attention / LoRA / Embedding 论文不卡公式</span></span>
<span class="line"><span>11-15  概率统计:看完会写 A/B 测试、不会被「p&lt;0.05 显著」这种说法骗</span></span>
<span class="line"><span>16-19  信息论:看完知道交叉熵为什么是分类损失、RLHF 里的 KL 在罚什么</span></span>
<span class="line"><span>20-24  优化:**最贴日常调参**,Adam 的 β1 β2 不再是&quot;抄默认值&quot;</span></span>
<span class="line"><span>25-30  离散:**给 security / algorithm / RL 兜底**,RSA / PageRank / MDP 都能看到底</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 05-10 + 16-19 + 20-23 这 14 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 Embedding 用 cosine 而不是欧氏距离,什么时候反过来&quot;</li><li>&quot;LoRA 的 rank=8 为什么够用,这个 rank 是 SVD 里的哪个 r&quot;</li><li>&quot;交叉熵损失里的 log 如果直接算会出什么问题,log-sum-exp 在解决什么&quot;</li><li>&quot;RLHF 里的 KL 罚项往哪个方向罚,β 调大调小分别会怎样&quot;</li><li>&quot;Adam 的 β1 / β2 / ε 各自在数学上对应什么,为什么默认是 0.9 / 0.999 / 1e-8&quot;</li></ul><p>能讲清楚一题这个系列就值了。</p><p>再加上 25-30 这 6 篇,你应该能看懂:</p><ul><li>&quot;RSA 的安全性为什么落在大整数分解,椭圆曲线为什么换了一个更难的问题&quot;</li><li>&quot;PageRank 的迭代为什么会收敛,这个收敛在线代里是什么定理&quot;</li><li>&quot;RL 的策略迭代 / 价值迭代,数学上就是马尔可夫链 + 不动点&quot;</li></ul><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li><strong>不写《高等数学》课本节选 / 不抄维基百科公式</strong>——课本和 Wiki 都在,本系列只补它们没串起来的&quot;为什么 + 工程对应&quot;</li><li>「先讲个数学史 / 牛顿莱布尼茨之争 / 希尔伯特问题」——直接进重点,故事只在脚注引用</li><li><strong>证明题、习题集</strong>——本系列零习题、零证明,看不懂证明完全可以学</li><li>「这个公式很优美」式的审美安利——读者关心&quot;调它会动什么&quot;,不关心你的情怀</li><li><strong>不画图就讲向量空间 / 概率分布 / 计算图 / 图论 / 马尔可夫链</strong>——这些<strong>不画图永远讲不清楚</strong></li><li>抄 PyTorch / NumPy 文档——文档在那儿,这里只补&quot;为什么 API 长这样&quot;</li><li>把 ML 算法的实现细节再讲一遍——那是 aiLearning 的活,本系列只往下挖到数学</li><li>把密码学协议讲完整——那是 securityLearning 的活,本系列只到「底下的数论」</li><li>「先复习一下集合论」式的过度铺垫——只在用到时一句话带过</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于&quot;读懂论文 + 调对超参 + 排查数值/统计错误&quot;</strong>——不是教你重证一遍中心极限定理,而是教你看到一段公式时,知道它对应代码里的哪一行、调它会动哪个指标。</p><p>所有数学描述限制在直觉、几何图与最小代码片段,<strong>不提供严格证明</strong>;所有工程映射都指向公开论文、开源系统(PyTorch / NumPy / Faiss / OpenSSL / NetworkX)或公开课程,不引用任何未公开的内部资料。</p><p><strong>面向 2026:</strong></p><ul><li>默认你已经会用 Python + NumPy / PyTorch,系列里不重复教</li><li>默认你已经在用 Claude / Cursor / Copilot 协助理解公式,系列里直接给「问 LLM 时该怎么提问」的最小关键词</li><li>默认你看的论文是 2020 年之后的(Transformer / LoRA / RLHF / Diffusion / Mamba),老论文只在脚注引用</li></ul><hr><h2 id="读完之后去哪" tabindex="-1">读完之后去哪 <a class="header-anchor" href="#读完之后去哪" aria-label="Permalink to &quot;读完之后去哪&quot;">​</a></h2><ul><li><strong>想再深 ML 数学</strong>:Bishop <em>PRML</em> + Goodfellow <em>Deep Learning</em> 第 II 部 + MacKay <em>Information Theory, Inference, and Learning Algorithms</em></li><li><strong>想再深线代</strong>:Strang <em>Introduction to Linear Algebra</em>(MIT 18.06)+ Trefethen <em>Numerical Linear Algebra</em></li><li><strong>想再深优化</strong>:Boyd <em>Convex Optimization</em>(配套斯坦福公开课)+ Nocedal <em>Numerical Optimization</em></li><li><strong>想再深概率</strong>:Wasserman <em>All of Statistics</em> + Murphy <em>Probabilistic Machine Learning</em></li><li><strong>想再深密码学</strong>:Boneh &amp; Shoup <em>A Graduate Course in Applied Cryptography</em>(免费 PDF)</li><li><strong>想动手</strong>:跟 <em>fast.ai</em> 的 Numerical Linear Algebra 课、karpathy 的 nn-zero-to-hero、3Blue1Brown 的「线代/微积分本质」系列(看图省一半时间)</li><li><strong>想再宽</strong>:等未来的 <strong>aiInfra</strong>(GPU / 推理引擎 / 分布式训练)和已有的 aiLearning,把这一层的数学接上系统工程</li></ul>`,61)])])}const c=t(l,[["render",e]]);export{g as __pageData,c as default};
